import{_ as i,o as t,c as a,ai as r}from"./chunks/framework.C4ntERNc.js";const u=JSON.parse('{"title":"Overview","description":"","frontmatter":{"title":"Overview","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"getting-started/overview.md","filePath":"getting-started/overview.md"}'),l={name:"getting-started/overview.md"};function s(o,e,n,d,c,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/getting-started/overview.md for this page in Markdown format</div><h1 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h1><p>A concise introduction to JZ-HDL: what it is, who it’s for, high‑level design goals, essential rules to know immediately, and pointers into the rest of the documentation.</p><hr><h2 id="what-is-jz-hdl" tabindex="-1">What is JZ-HDL? <a class="header-anchor" href="#what-is-jz-hdl" aria-label="Permalink to “What is JZ-HDL?”">​</a></h2><p>JZ-HDL is a hardware description language designed for clear, analyzable, and synthesis‑friendly RTL. It emphasizes:</p><ul><li>Deterministic net semantics (single active driver per net/path)</li><li>Strong, flow‑sensitive checks that prevent ambiguous hardware (floating nets, combinational loops, multi‑driver races)</li><li>Explicit, compile‑time width &amp; bit‑state semantics (x/z handling, literal intrinsic widths)</li><li>Practical on‑chip constructs: registers, parameterized memories (MEM), tri‑state INOUTs, and explicit CDC primitives</li></ul><p>Think of JZ-HDL as a small, strict RTL language that trades permissiveness for safer, more predictable synthesis and verification.</p><hr><h2 id="target-audience" tabindex="-1">Target audience <a class="header-anchor" href="#target-audience" aria-label="Permalink to “Target audience”">​</a></h2><ul><li>RTL designers who want stricter, safer language semantics than raw Verilog/SystemVerilog</li><li>Tool authors and synthesizers needing an unambiguous net model</li><li>FPGA/ASIC engineers who want explicit memory, clock‑domain, and pin mapping constructs</li><li>Educators teaching deterministic digital design patterns</li></ul><hr><h2 id="design-goals" tabindex="-1">Design goals <a class="header-anchor" href="#design-goals" aria-label="Permalink to “Design goals”">​</a></h2><ul><li>Make illegal hardware obvious at compile time (floating nets, driver conflicts, combinational loops).</li><li>Keep syntax and semantics small and explicit — fewer surprises for synthesis.</li><li>Provide high‑level, synthesis‑aware helpers (intrinsics like uadd/umul, MEM modes, CDC primitives).</li><li>Ensure compile‑time determinism for widths and indices (clog2, widthof, CONST/CONFIG separation).</li></ul><hr><h2 id="must‐know-rules-top‐level" tabindex="-1">Must‑know rules (top‑level) <a class="header-anchor" href="#must‐know-rules-top‐level" aria-label="Permalink to “Must‑know rules (top‑level)”">​</a></h2><p>These are the things every author should absorb first.</p><ul><li><p>Observability Rule</p><ul><li>Any expression containing <code>x</code> bits must be provably masked before reaching an observable sink (register reset/init, MEM init, module OUT/INOUT, top pins). If not provably masked, compilation fails.</li></ul></li><li><p>Exclusive Assignment Rule</p><ul><li>For every assignable signal (REGISTER, WIRE, OUT/INOUT port), every execution path through a block must assign each bit at most once. The compiler enforces this with flow‑sensitive analysis.</li></ul></li><li><p>Driver model</p><ul><li>A net must have exactly zero or one active driver per execution path, unless tri‑stated where all but one driver produce <code>z</code> for each bit.</li><li>Multiple potential drivers are allowed only if they are mutually tri‑stated except one.</li></ul></li><li><p>Strict width handling</p><ul><li>Most binary operators require identical operand widths.</li><li>Use explicit modifiers (<code>=z</code>, <code>=s</code>, <code>&lt;=z</code>, <code>&lt;=s</code>, <code>=&gt;z</code>, <code>=&gt;s</code>) to extend narrower operands; truncation is never implicit.</li><li>Unsized literals are forbidden.</li></ul></li><li><p>Register locality and clocks</p><ul><li>All registers driven by a particular clock belong to a single SYNCHRONOUS block per clock (no multiple blocks per same clock).</li><li>Clock‑domain crossings require explicit CDC entries; registers are bound to a &quot;home domain&quot;.</li></ul></li><li><p>Memory semantics</p><ul><li>MEM supports ASYNC and SYNC read ports and synchronous write ports.</li><li>Write mode (WRITE_FIRST / READ_FIRST / NO_CHANGE) determines read behavior when a read and write target the same address in one cycle.</li><li>Mem inits must be deterministic (no <code>x</code>).</li></ul></li></ul><hr><h2 id="what-s-new-version-1-0-highlights" tabindex="-1">What&#39;s new / version 1.0 highlights <a class="header-anchor" href="#what-s-new-version-1-0-highlights" aria-label="Permalink to “What&#39;s new / version 1.0 highlights”">​</a></h2><ul><li>Strict Observability Rule for <code>x</code> propagation</li><li>Flow‑sensitive Exclusive Assignment enforcement (PED)</li><li>Explicit CDC primitives (BIT, BUS, FIFO) with home‑domain binding</li><li>A small but expressive set of intrinsics (uadd/sadd/umul/smul/gbit/sbit/gslice/sslice)</li><li>Simplified, deterministic MEM model with ASYNC/SYNC read ports and explicit write modes</li><li>Compile-time templates (<code>@template</code>/<code>@apply</code>) for reusable logic patterns with scratch wires and unrolling</li></ul><hr><h2 id="how-to-read-the-documentation" tabindex="-1">How to read the documentation <a class="header-anchor" href="#how-to-read-the-documentation" aria-label="Permalink to “How to read the documentation”">​</a></h2><ul><li><strong>Newcomers:</strong> Start with the <a href="/jz-hdl/examples/counter.html">Examples</a> to see working JZ-HDL code, then read the guide pages under Reference Manual.</li><li><strong>Verilog/VHDL users:</strong> Read the <a href="/jz-hdl/reference-manual/migration.html">Migration Guide</a> for a side-by-side comparison of concepts and idioms.</li><li><strong>Reference lookup:</strong> The <a href="/jz-hdl/reference-manual/formal-reference/core-concepts.html">Formal Reference</a> section provides concise, normative rules for every language construct.</li></ul>',24)])])}const p=i(l,[["render",s]]);export{u as __pageData,p as default};
